Exercise: Two-Fer (two-fer)
Difficulty: 1/9

Instructions:
# Instructions

Your task is to determine what you will say as you give away the extra cookie.

If you know the person's name (e.g. if they're named Do-yun), then you will say:

```text
One for Do-yun, one for me.
```

If you don't know the person's name, you will say _you_ instead.

```text
One for you, one for me.
```

Here are some examples:

| Name   | Dialogue                    |
| :----- | :-------------------------- |
| Alice  | One for Alice, one for me.  |
| Bohdan | One for Bohdan, one for me. |
|        | One for you, one for me.    |
| Zaphod | One for Zaphod, one for me. |


Starter file:
```zig
pub fn twoFer(buffer: []u8, name: ?[]const u8) ![]u8 {
    _ = buffer;
    _ = name;
    @compileError("respond with the appropriate message given a particular name");
}

```

Tests that will be run with `zig test`:
```zig
const std = @import("std");
const testing = std.testing;

const two_fer = @import("two_fer.zig");

const buffer_size = 100;

test "no name given" {
    var response: [buffer_size]u8 = undefined;
    const expected = "One for you, one for me.";
    const actual = try two_fer.twoFer(&response, null);
    try testing.expectEqualStrings(expected, actual);
}

test "a name given" {
    var response: [buffer_size]u8 = undefined;
    const expected = "One for Alice, one for me.";
    const actual = try two_fer.twoFer(&response, "Alice");
    try testing.expectEqualStrings(expected, actual);
}

test "another name given" {
    var response: [buffer_size]u8 = undefined;
    const expected = "One for Bob, one for me.";
    const actual = try two_fer.twoFer(&response, "Bob");
    try testing.expectEqualStrings(expected, actual);
}

```

```zig
pub fn twoFer(buffer: []u8, name:?[]const u8)![]u8 {
    const base = "One for ";
    const suffix = ", one for me.";

    const name_str = if (name) |n| n else "you";

    const base_len = base.len;
    const name_len = name_str.len;
    const suffix_len = suffix.len;

    const total_len = base_len + name_len + suffix_len;

    if (total_len > buffer.len) {
        return error.BufferTooSmall;
    }

    var i: usize = 0;

    // Copy base
    for (base) |c| {
        buffer[i] = c;
        i += 1;
    }

    // Copy name or "you"
    for (name_str) |c| {
        buffer[i] = c;
        i += 1;
    }

    // Copy suffix
    for (suffix) |c| {
        buffer[i] = c;
        i += 1;
    }

    return buffer[0:i];
}

```

